#include <bits/stdc++.h>
using namespace std;
int c,f1,f2,d,l,r,a[2003],s[2003];
int main(){
    cin>>c>>f1>>f2>>d;
    while(c--){
        cin>>l>>r;
        if(l<=d){
            if(r>d)r=d;
            a[l]+=1;
            a[r+1]-=1;
        }
    }
    for(int i=1;i<=d;i++){
    	s[i]=s[i-1]+a[i];
    	//cout<<s[i]<<' '; 
	}
	//cout<<endl;
    for(int i=d;i;i--){
        f2+=s[i];
        if(f2>=f1){
            cout<<i;
            return 0;
        }
    }
    return 0;
}
